class Solution {
public:
    vector<int> popcountDepth(vector<long long>& nums, vector<vector<long long>>& queries) {
        vector<int> depths(nums.size());
        for (int i = 0; i < nums.size(); ++i) {
            depths[i] = getDepth(nums[i]);
        }

        vector<int> answer;
        for (const auto& query : queries) {
            if (query[0] == 1) {
                int l = query[1], r = query[2], k = query[3];
                int count = 0;
                for (int i = l; i <= r; ++i) {
                    if (depths[i] == k) ++count;
                }
                answer.push_back(count);
            } else {
                int idx = query[1], val = query[2];
                depths[idx] = getDepth(val);
                nums[idx] = val;
            }
        }
        return answer;
    }

    int getDepth(long long x) {
        int depth = 0;
        while (x != 1) {
            x = __builtin_popcountll(x);
            ++depth;
        }
        return depth;
    }
};
